import{_ as s,H as p,f as n,i as e}from"./chunks/framework.BHvCMIhP.js";const r=JSON.parse('{"title":"HTTPS 与证书:SSL/TLS,CA,自动续期,证书错误","description":"","frontmatter":{},"headers":[],"relativePath":"cloudBasicsLearning/05-HTTPS与证书.md","filePath":"cloudBasicsLearning/05-HTTPS与证书.md","lastUpdated":1779015580000}'),l={name:"cloudBasicsLearning/05-HTTPS与证书.md"};function t(i,a,o,c,d,h){return p(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="https-与证书-ssl-tls-ca-自动续期-证书错误" tabindex="-1">HTTPS 与证书:SSL/TLS,CA,自动续期,证书错误 <a class="header-anchor" href="#https-与证书-ssl-tls-ca-自动续期-证书错误" aria-label="Permalink to &quot;HTTPS 与证书:SSL/TLS,CA,自动续期,证书错误&quot;">​</a></h1><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>HTTPS 就是在 HTTP 外面加了一层加密和身份验证,让浏览器确认&quot;我连接的是这个域名对应的真实服务&quot;,并且传输内容不容易被中间人偷看或篡改.</p><p>证书就是这套身份验证里的凭证.它告诉浏览器:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这个网站声称自己是 example.com</span></span>
<span class="line"><span>这个声明由可信 CA 签发</span></span>
<span class="line"><span>证书还在有效期内</span></span>
<span class="line"><span>访问的域名和证书里的域名匹配</span></span></code></pre></div><p>最容易混淆的是 SSL 和 TLS.日常大家还会说&quot;SSL 证书&quot;,但现代 HTTPS 实际主要使用 TLS.你不需要纠结叫法,只要知道它们解决的是加密传输和网站身份验证.</p><p>对小团队来说,HTTPS 不是高级功能,而是上线标配.没有 HTTPS,登录,支付,后台,Cookie,OAuth 回调,浏览器权限 API 都会遇到安全或兼容问题.</p><h2 id="放在系统哪里" tabindex="-1">放在系统哪里 <a class="header-anchor" href="#放在系统哪里" aria-label="Permalink to &quot;放在系统哪里&quot;">​</a></h2><p>HTTPS 发生在浏览器拿到 IP 之后,发送 HTTP 请求之前.</p><p>一次访问可以简化成:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户访问 https://www.example.com</span></span>
<span class="line"><span>  -&gt; DNS 返回入口地址</span></span>
<span class="line"><span>  -&gt; 浏览器连接 443 端口</span></span>
<span class="line"><span>  -&gt; 服务器发送证书</span></span>
<span class="line"><span>  -&gt; 浏览器验证证书是否合法</span></span>
<span class="line"><span>  -&gt; 双方协商加密参数</span></span>
<span class="line"><span>  -&gt; 开始发送 HTTP 请求</span></span></code></pre></div><p>在现代云部署里,证书不一定装在你的应用服务器上.它可能放在:</p><ul><li>CDN 边缘节点.</li><li>负载均衡.</li><li>API Gateway.</li><li>反向代理.</li><li>前端托管平台.</li><li>你自己的云服务器.</li></ul><p>这叫 TLS 终止.意思是 HTTPS 加密连接在某一层结束,这一层再把请求转发给后面的服务.</p><p>常见结构是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户浏览器</span></span>
<span class="line"><span>  -&gt; HTTPS 到 CDN / 网关</span></span>
<span class="line"><span>  -&gt; CDN / 网关验证证书并解密</span></span>
<span class="line"><span>  -&gt; HTTP 或 HTTPS 转发到源站</span></span>
<span class="line"><span>  -&gt; 应用处理请求</span></span></code></pre></div><p>这里有一个重要安全点:用户到 CDN 是 HTTPS,不代表 CDN 到源站也一定是 HTTPS.如果源站和 CDN 之间走公网 HTTP,仍然有风险.小团队至少要知道自己的 HTTPS 到底终止在哪里.</p><h2 id="常见套餐和使用限制" tabindex="-1">常见套餐和使用限制 <a class="header-anchor" href="#常见套餐和使用限制" aria-label="Permalink to &quot;常见套餐和使用限制&quot;">​</a></h2><p>HTTPS 现在经常被平台自动处理,但限制仍然不少.</p><h3 id="_1-自动证书通常免费-但有边界" tabindex="-1">1. 自动证书通常免费,但有边界 <a class="header-anchor" href="#_1-自动证书通常免费-但有边界" aria-label="Permalink to &quot;1. 自动证书通常免费,但有边界&quot;">​</a></h3><p>很多托管平台,CDN,云网关会自动申请和续期证书.对个人网站和早期 SaaS 来说,这通常够用.</p><p>但自动证书依赖域名验证.如果 DNS 没配好,域名没有正确指向平台,CAA 记录限制了签发机构,证书就可能申请失败.</p><p>一个常见场景:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你把 www.example.com 绑定到托管平台</span></span>
<span class="line"><span>平台提示等待证书签发</span></span>
<span class="line"><span>你等了几个小时还是失败</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最后发现:</span></span>
<span class="line"><span>DNS 里 www 仍然指向旧平台</span></span>
<span class="line"><span>新平台无法证明你控制这个域名</span></span>
<span class="line"><span>证书自然签不下来</span></span></code></pre></div><p>这不是 HTTPS 本身的问题,而是 DNS 和域名验证没完成.</p><h3 id="_2-证书有有效期-续期失败会直接影响访问" tabindex="-1">2. 证书有有效期,续期失败会直接影响访问 <a class="header-anchor" href="#_2-证书有有效期-续期失败会直接影响访问" aria-label="Permalink to &quot;2. 证书有有效期,续期失败会直接影响访问&quot;">​</a></h3><p>证书过期后,浏览器会给出明显警告,用户基本不会继续访问.对于登录页,支付页,后台系统,这等于生产事故.</p><p>自动续期可以减少风险,但不是&quot;永远不用管&quot;.续期可能因为 DNS 变更,验证文件丢失,平台账号异常,CA 限制而失败.</p><p>小团队应该至少有一个监控:证书还有多少天过期.</p><h3 id="_3-证书必须匹配域名" tabindex="-1">3. 证书必须匹配域名 <a class="header-anchor" href="#_3-证书必须匹配域名" aria-label="Permalink to &quot;3. 证书必须匹配域名&quot;">​</a></h3><p>证书签给 <code>www.example.com</code>,不一定覆盖 <code>example.com</code>.证书签给 <code>*.example.com</code>,通常覆盖 <code>api.example.com</code>,但不覆盖 <code>example.com</code>,也不覆盖 <code>a.b.example.com</code>.</p><p>所以你上线时要检查:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://example.com</span></span>
<span class="line"><span>https://www.example.com</span></span>
<span class="line"><span>https://api.example.com</span></span></code></pre></div><p>它们每一个需要的证书覆盖范围可能不同.</p><h3 id="_4-https-错误不只一种" tabindex="-1">4. HTTPS 错误不只一种 <a class="header-anchor" href="#_4-https-错误不只一种" aria-label="Permalink to &quot;4. HTTPS 错误不只一种&quot;">​</a></h3><p>浏览器报&quot;不安全&quot;时,不要只说&quot;证书坏了&quot;.常见原因包括:</p><ul><li>证书过期.</li><li>证书域名不匹配.</li><li>中间证书链不完整.</li><li>使用了不再安全的 TLS 版本或加密套件.</li><li>用户本地时间错误.</li><li>CDN 到源站的证书模式配置不对.</li><li>HTTP 和 HTTPS 重定向循环.</li></ul><p>对于使用 Cloudflare 这类 CDN 的团队,还要特别注意源站证书模式.边缘证书正常,不代表源站证书正常.某些&quot;灵活 HTTPS&quot;模式会让浏览器到 CDN 是 HTTPS,但 CDN 到源站是 HTTP,这可能隐藏真实问题.</p><h2 id="小团队建议" tabindex="-1">小团队建议 <a class="header-anchor" href="#小团队建议" aria-label="Permalink to &quot;小团队建议&quot;">​</a></h2><p>小团队的原则是:优先用平台托管证书,但必须知道证书在哪里,谁负责续期,覆盖哪些域名.</p><p>最低限度建议:</p><ul><li>所有正式入口都启用 HTTPS.</li><li>让 HTTP 自动 301 跳转到 HTTPS.</li><li>使用托管平台或 CDN 的自动证书,减少手工续期.</li><li>检查根域名,<code>www</code>,<code>api</code> 是否都被证书覆盖.</li><li>监控证书过期时间.</li><li>不要为了临时省事关闭证书校验.</li><li>源站如果走公网,尽量也使用 HTTPS.</li></ul><p>什么时候自动证书够用?</p><p>个人网站,落地页,小型 SaaS,前后端分离项目,平台自动证书通常足够.你需要做的是正确绑定域名,保持 DNS 指向正确,确认自动续期正常.</p><p>什么时候需要更专业的方案?</p><p>当你有多个业务域名,企业内网服务,私有 CA,客户端证书认证,合规要求,证书统一治理需求时,就需要更系统的证书管理.此时重点不是&quot;买更贵的证书&quot;,而是证书生命周期,权限,审计和自动化.</p><p>一个常见的早期稳定方案是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>域名 DNS -&gt; CDN / 托管平台</span></span>
<span class="line"><span>HTTPS 证书 -&gt; 平台自动签发和续期</span></span>
<span class="line"><span>源站 -&gt; 只允许 CDN 或网关访问</span></span>
<span class="line"><span>HTTP -&gt; 统一跳转 HTTPS</span></span>
<span class="line"><span>证书监控 -&gt; 提前提醒过期</span></span></code></pre></div><p>这样能避开手工上传证书,忘记续期,证书链配置错误这些高频事故.</p><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>HTTPS 解决的是加密传输和网站身份验证;小团队可以依赖平台自动证书,但必须知道证书覆盖哪些域名,在哪里终止,是否会自动续期.</p>`,51)])])}const u=s(l,[["render",t]]);export{r as __pageData,u as default};
